const rows = msg.payload;
if (!Array.isArray(rows) || rows.length === 0) {
    node.warn('No printers found in database');
    return null;
}

const printers = rows.map(r => ({
    name:          r.name,
    displayName:   r.display_name,
    type:          r.type,
    ip:            r.ip,
    equipment:     r.equipment,
    mqttKey:       r.mqtt_key || r.name,
    printProtocol: r.print_protocol || 'IPP',
    printPort:     r.print_port     || 631,
    rawPort:       r.raw_port       || 9100,
    snmpEnabled:   r.snmp_enabled   !== false,
    snmpCommunity: r.snmp_community || 'public',
    snmpVersion:   r.snmp_version   || 2,
    plcHost:       r.plc_host       || global.get('plcIp')   || '192.168.1.10',
    plcSlot:       r.plc_slot       != null ? r.plc_slot : (parseInt(global.get('plcSlot')) || 0),
    location:      r.location       || '',
    config:        r.config         || {},
    lastSeen:      null,
}));

global.set('printerList', printers);
flow.set('printerList', printers);   // keep flow context in sync for backward compat

// Default path where to get the files
global.set('printAssetsPath', '/home/systemex/prod');

// Pre-seed dashboard rows with location + equipment
const existingDash = flow.get('dash_printers') || {};
printers.forEach(p => {
    if (!existingDash[p.name]) existingDash[p.name] = {};
    existingDash[p.name].name = p.name;
    existingDash[p.name].equipment = p.equipment || '';
    existingDash[p.name].location = p.location || '';
});
flow.set('dash_printers', existingDash);

node.log('Loaded ' + printers.length + ' printer(s) from database');
msg.payload = printers;
return msg;

global.set('plcDriver', env.get('PLC_DRIVER') || 'eip');
global.set('plcIp', env.get('PLC_IP') || '192.168.1.10');
global.set('plcSlot', env.get('PLC_SLOT') || '0');
global.set('opcEndpoint', env.get('OPC_ENDPOINT') || 'opc.tcp://192.168.1.10:4840');

global.set('printerConfig', {

    jobTimeoutMs: 2 * 60 * 1000,
    logRetentionDays: 30,
    dashboardJobCount: 20,

    // Tags to subscribe per type
    subscribeTags: {
        EPSON_CW6500: ['DataReady', 'Print', 'File_Path'],
        ZEBRA_ZT421: ['DataReady', 'Print', 'File_Path'],
        BROTHER_HLL5210: ['DataReady', 'Print', 'Product_Name', 'Product_Qty', 'BAC_Number'],
        ZEBRA_ZE511R: ['SendData', 'File_Path']
    },

    // Tag values to write on startup per type
    startupTags: {
        EPSON_CW6500: { ComOK: false, Available: true, JobDone: false, Label_RDY: false, Alarm: 0, Warning: 0 },
        ZEBRA_ZT421: { ComOK: false, Available: true, JobDone: false, Label_RDY: false, Alarm: 0, Warning: 0 },
        BROTHER_HLL5210: { ComOK: false, Available: true, JobDone: false, Alarm: 0, Warning: 0 },
        ZEBRA_ZE511R: { ComOK: false, SendDATADone: false }
    }

});
return msg;

const rows = msg.payload;
if (!Array.isArray(rows) || rows.length === 0) {
    node.warn('No zones found in database');
    global.set('zoneList', []);
    return null;
}

const zones = rows.map(r => ({
    name:        r.name,
    displayName: r.display_name || r.name,
