const rows = msg.payload;
if (!Array.isArray(rows) || rows.length === 0) {
    node.warn('No equipment found in database');
    global.set('equipmentList', []);
    return null;
}

const equipment = rows.map(r => ({
    name:        r.name,
    displayName: r.display_name || r.name,
