const driver = global.get('plcDriver') || env.get('PLC_DRIVER') || 'eip';
node.log('Checking driver tab states for: ' + driver);
msg.driver = driver;
msg.token = env.get('NR_API_TOKEN') || '';
msg.headers = {
    'Node-RED-API-Version': 'v2',
    'Authorization': 'Bearer ' + msg.token
};
return msg;

const driver = msg.driver;
const token  = msg.token;
const flows  = msg.payload && msg.payload.flows;
if (!flows) { node.warn('Could not read flows from admin API'); return null; }

const TAB_DRIVER = { 'drv_eip_tab': 'eip', 'drv_s7_tab': 's7', 'drv_opc_tab': 'opc' };
let needsUpdate = false;
const updated = flows.map(n => {
    if (n.type !== 'tab' || !TAB_DRIVER[n.id]) return n;
    const shouldEnable = TAB_DRIVER[n.id] === driver;
    const isDisabled   = n.disabled === true;
    if (shouldEnable === isDisabled) {
        needsUpdate = true;
        return {...n, disabled: !shouldEnable};
    }
    return n;
});
if (!needsUpdate) { node.log('Driver tab already correct: ' + driver); return null; }
node.log('Enabling driver tab: ' + driver);
msg.payload = { flows: updated };
msg.headers = {
    'Content-Type': 'application/json',
    'Node-RED-API-Version': 'v2',
    'Node-RED-Deployment-Type': 'reload',
    'Authorization': 'Bearer ' + token
};
return msg;

if (global.get('plcDriver') !== 'eip') return null;
const equipmentList = global.get('equipmentList') || [];
if (equipmentList.length === 0) { node.warn('equipmentList not loaded yet'); return null; }

const tags = [];
for (const eq of equipmentList) {
    const n = eq.name;
    const c = eq.config || {};
    tags.push(n + '.Status.Alarm_Active');
    if (c.hasPe1)         tags.push(n + '.PE[1].In.Presence');
    if (c.hasPe2)         tags.push(n + '.PE[2].In.Presence');
    if (c.hasCurrentStep) tags.push(n + '.SeqOperation_CurrentStep');
    if (c.hasMt1)         tags.push(n + '.MT[1].HMI.In.Speed');
    if (c.hasVg1)         tags.push(n + '.VG[1].In.PSS');
    const cyls = c.cylinders || 0;
    for (let i = 1; i <= cyls; i++) {
        tags.push(n + '.CY[' + i + '].In.RSX');
        tags.push(n + '.CY[' + i + '].In.RSR');
    }
}

msg.payload = { tags };
node.log('Subscribing to ' + tags.length + ' equipment tags');
return msg;

if (global.get('plcDriver') !== 'eip') return null;
const eq = msg.topic.split('/')[1];
msg.eqName = eq;
msg.payload = { tags: [{ name: eq + '.HMI.In.Reset_Rqst', value: true, type: 'BOOL' }] };
return msg;

if (global.get('plcDriver') !== 'eip') return null;
const zoneList = global.get('zoneList') || [];
if (zoneList.length === 0) { node.warn('zoneList not loaded yet'); return null; }
const zones = zoneList.map(z => z.name);
const suffixes = [
    'Status.Alarm_Active', 'Status.Stopping', 'Status.Stopped',
    'Status.Init_Done', 'Status.Paused', 'Status.Rearmed',
    'Status.Rearming', 'Status.Running', 'Status.Disabled',
    'Prod_Status.Running',
    'Status.EStops_OK', 'Status.EStops_Robots_OK', 'Status.Keys_OK',
    'Status.Doors_Closed_OK', 'Status.Doors_Locked_OK', 'Status.Light_Curtains_OK',
    'Status.Coded_Magnets_OK', 'Status.Light_Curtains_Armed', 'Status.Air_Pressure_OK',
    'Status.Safety_OK', 'Status.Conditons_Arming_OK', 'Status.Armed_Feedback_OK',
    'Status.Dump_Valve_OK', 'Status.Relay_Estop_OK', 'Status.Relay_Area_OK'
];
const tags = zones.flatMap(z => suffixes.map(s => z + '.' + s));
msg.payload = { tags };
return msg;

if (global.get('plcDriver') !== 'eip') return null;
const parts = msg.topic.split('/');
const zone = parts[1];
msg.payload = { tags: [{ name: zone + '.Reset_Alarms', value: true, type: 'BOOL' }] };
return msg;

if (global.get('plcDriver') !== 'eip') return null;
// Client sends {tags:[...], action:'subscribe'|'clear'}
// eip-subscription expects msg.payload = {tags:[...]} or {action:'clear',tags:[]}
return msg;

if (!msg.payload || !msg.payload.ok) return null;
const tags = msg.payload.tags || {};
const msgs = Object.entries(tags)
    .filter(([, value]) => value !== null && value !== undefined)
    .map(([name, value]) => ({
        topic: 'plc/tags/' + name,
        payload: value,
        retain: false
    }));
return msgs.length ? [msgs] : null;

if (global.get('plcDriver') !== 'eip') return null;
// payload: {tags:[{name,value,type}]} — matches eip-write format
return msg;

if (global.get('plcDriver') !== 'eip') return null;
// payload: {tag:{name:'...'}} — matches eip-pulse format
return msg;

if (global.get('plcDriver') !== 'eip') return null;
// payload: {tag:{name:'...'}} — matches eip-toggle format
return msg;

// Routes variables by prefix: EQ*→equipment, AR*→zone, rest→machine
// Also caches all values for toggle operations
if (!msg.payload || typeof msg.payload !== 'object') return [null,null,null];
const tags = msg.payload;
// Update flow cache for toggle
const cache = flow.get('s7_cache') || {};
Object.assign(cache, tags);
flow.set('s7_cache', cache);

const eq = {}, zone = {}, machine = {};
for (const [k,v] of Object.entries(tags)) {
    if      (k.startsWith('EQ')) eq[k]      = v;
    else if (k.startsWith('AR')) zone[k]    = v;
    else                          machine[k] = v;
}
return [
    Object.keys(eq).length      ? {payload:eq}      : null,
    Object.keys(zone).length    ? {payload:zone}    : null,
    Object.keys(machine).length ? {payload:machine} : null
];

const tags = msg.payload;
return Object.entries(tags).map(([fullName, value]) => {
    const dot = fullName.indexOf('.');
    return { topic:'equipment/update',
             payload: JSON.stringify({ name:fullName.slice(0,dot), variable:fullName.slice(dot+1), value }) };
});

const tags = msg.payload;
return Object.entries(tags).map(([fullName, value]) => {
    const dot = fullName.indexOf('.');
    const zone = fullName.slice(0,dot);
    const field = fullName.slice(dot+1);
    return { topic:'zone/'+zone+'/'+field, payload:value };
});

if (global.get('plcDriver') !== 's7') return null;
const tags = msg.payload;
// Map DB51 variables to machine/* MQTT topics
// Adapt variable names to match your vartable entries
const stateMap = {
    'HM_DB.State':         'machine/state',
    'HM_DB.AlarmByte':     'machine/alarm/general',
    'HM_DB.ManualMode':    'machine/mode/manual',
    'HM_DB.RecipeName':    'machine/recipe/name',
};
const msgs = [];
for (const [varName, value] of Object.entries(tags)) {
    const topic = stateMap[varName];
    if (topic) msgs.push({ topic, payload: value, retain: true });
}
return msgs.length ? msgs : null;

if (global.get('plcDriver') !== 's7') return null;
const cmd = msg.topic.replace('machine/cmd/','');
// Map command to S7 variable name in vartable. Adapt to your DB layout (see HM_DB[51] plan).
const cmdMap = {
    'start':       'HM_DB.Cmd_Start',
    'stop':        'HM_DB.Cmd_Stop',
    'abort':       'HM_DB.Cmd_Abort',
    'reset':       'HM_DB.Cmd_Reset',
    'mute':        'HM_DB.Cmd_Mute',
    'manual':      'HM_DB.ManualMode',
    'fwd':         'HM_DB.Cmd_Fwd',
    'bwd':         'HM_DB.Cmd_Bwd',
    'jog_fwd':     'HM_DB.Cmd_JogFwd',
    'jog_bwd':     'HM_DB.Cmd_JogBwd',
    'load_recipe': 'HM_DB.Cmd_LoadRecipe',
};
const varName = cmdMap[cmd];
if (!varName) { node.warn('Unknown S7 cmd: ' + cmd); return null; }
msg.variable = varName;
msg.payload  = msg.payload;
return msg;

if (global.get('plcDriver') !== 's7') return null;
const eq = msg.topic.split('/')[1];
msg.eqName   = eq;
// Variable name must match entry in vartable, e.g. 'EQ11501.HMI_Reset'
msg.variable = eq + '.HMI_Reset';
msg.payload  = true;
return msg;

msg.variable = msg.eqName + '.HMI_Reset';
msg.payload = false;
return msg;

if (global.get('plcDriver') !== 's7') return null;
const zone = msg.topic.split('/')[1];
msg.variable = zone + '.Reset_Alarms';
msg.payload  = true;
return msg;

if (global.get('plcDriver') !== 's7') return null;
// S7 is polling-based — all vartable variables are published continuously by the s7 in node.
// Dynamic subscription is not supported; ensure required tags are in the vartable.
node.log('S7 plc/subscribe received — tags are read from vartable continuously');
return null;

if (global.get('plcDriver') !== 's7') return null;
const tags = msg.payload?.tags || (msg.payload?.tag ? [msg.payload.tag] : []);
if (!tags.length) return null;
// Emit one msg per tag (s7 out writes one variable at a time)
return tags.map(t => ({ ...msg, variable: t.name, payload: t.value }));

if (global.get('plcDriver') !== 's7') return null;
const tag = msg.payload?.tag;
if (!tag?.name) return null;
msg.pulseName = tag.name;
msg.variable  = tag.name;
msg.payload   = true;
return msg;

msg.variable = msg.pulseName;
msg.payload = false;
return msg;

if (global.get('plcDriver') !== 's7') return null;
const tag = msg.payload?.tag;
if (!tag?.name) return null;
// Read cached value from flow context (updated by s7 in via Route function)
const cached = flow.get('s7_cache') || {};
const current = cached[tag.name];
msg.variable = tag.name;
msg.payload  = (current === undefined) ? true : !current;
return msg;

// Build the list of OPC-UA Node IDs to subscribe to.
// Adapt namespace (ns=) and path prefix to your CODESYS project.
const cfg = global.get('plcConfig') || {};
const equipmentList = global.get('equipmentList') || [];
const zoneList      = global.get('zoneList')      || [];

const items = [];

// Machine status nodes (from plcConfig.statusNodes)
for (const [topic, nodeId] of Object.entries(cfg.statusNodes || {})) {
    items.push({ name: topic, nodeId });
}

// Equipment nodes — adapt variable suffixes to your CODESYS GVL structure
const EQ_VARS = ['PE1_Presence','PE2_Presence','CurrentStep','Speed','SuctionCup',
                 'CY1_Entered','CY1_Exited','CY2_Entered','CY2_Exited'];
for (const eq of equipmentList) {
    const base = 'ns=4;s=|var|Application.GVL.Equipment.' + eq.name;
    for (const v of EQ_VARS) {
        items.push({ name: eq.name + '.' + v, nodeId: base + '.' + v });
    }
}

// Zone nodes — adapt suffixes to your CODESYS GVL structure
const ZONE_VARS = ['Status_Alarm','Status_Running','Status_Stopped','Status_Safety'];
for (const z of zoneList) {
    const base = 'ns=4;s=|var|Application.GVL.' + z.name;
    for (const v of ZONE_VARS) {
        items.push({ name: z.name + '.' + v, nodeId: base + '.' + v });
    }
}

msg.payload = items;
msg.action  = 'subscribe';
return msg;

// OpcUa-Client subscribe outputs: msg.topic=nodeId, msg.payload=value
const nodeId = msg.topic || '';
const value  = msg.payload;

// Equipment: contains '.Equipment.EQ'
if (/\.Equipment\.EQ/.test(nodeId)) {
    const parts = nodeId.split('.');
    const eqIdx = parts.findIndex(p => /^EQ\d+/.test(p));
    if (eqIdx > -1) {
        const name     = parts[eqIdx];
        const variable = parts.slice(eqIdx+1).join('.');
        return [{ topic:'equipment/update', payload:JSON.stringify({name,variable,value}) }, null, null];
    }
}
// Zone: contains AR followed by digits
const zoneM = nodeId.match(/\.(AR\d+)\.(.+)/);
if (zoneM) {
    return [null, { topic:'zone/'+zoneM[1]+'/'+zoneM[2], payload:value }, null];
}
// Machine status: mapped from topic stored in msg.topic
const cfg = global.get('plcConfig') || {};
for (const [topic, nid] of Object.entries(cfg.statusNodes || {})) {
    if (nid === nodeId) {
        return [null, null, { topic, payload:value, retain:true }];
    }
}
return null;

if (global.get('plcDriver') !== 'opc') return null;
const cfg = global.get('plcConfig') || {};
const topic = msg.topic; // machine/cmd/start etc.
const nodeId = cfg.cmdNodes?.[topic];
if (!nodeId) { node.warn('No OPC node ID for: ' + topic); return null; }
msg.topic   = nodeId;
msg.action  = 'write';
msg.payload = msg.payload;
return msg;

if (global.get('plcDriver') !== 'opc') return null;
const eq = msg.topic.split('/')[1];
msg.eqName  = eq;
msg.topic   = 'ns=4;s=|var|Application.GVL.Equipment.' + eq + '.HMI.In.Reset_Rqst';
msg.action  = 'write';
msg.payload = true;
return msg;

msg.topic   = 'ns=4;s=|var|Application.GVL.Equipment.' + msg.eqName + '.HMI.In.Reset_Rqst';
msg.action  = 'write';
msg.payload = false;
return msg;

if (global.get('plcDriver') !== 'opc') return null;
const zone  = msg.topic.split('/')[1];
msg.topic   = 'ns=4;s=|var|Application.GVL.' + zone + '.Reset_Alarms';
msg.action  = 'write';
msg.payload = true;
return msg;

if (global.get('plcDriver') !== 'opc') return null;
const action = msg.payload?.action;
const tags   = msg.payload?.tags || [];
if (action === 'clear' || !tags.length) return null;
// Filter valid OPC-UA node IDs (must start with ns=)
const validTags = tags.filter(t => typeof t === 'string' && t.startsWith('ns='));
if (!validTags.length) return null;
msg.payload = validTags.map(name => ({ name, nodeId: name }));
msg.action  = 'subscribe';
return msg;

msg.topic   = 'plc/tags/' + (msg.topic || '').split(';s=').pop();
msg.payload = msg.payload;
return msg;

if (global.get('plcDriver') !== 'opc') return null;
const cfg  = global.get('plcConfig') || {};
const tags = msg.payload?.tags || (msg.payload?.tag ? [msg.payload.tag] : []);
return tags.map(t => ({
    ...msg,
    topic:   cfg.nodeMap?.[t.name] || t.name,
    action:  'write',
    payload: t.value
}));

if (global.get('plcDriver') !== 'opc') return null;
const cfg = global.get('plcConfig') || {};
const tag = msg.payload?.tag;
if (!tag?.name) return null;
msg.pulseTopic = cfg.nodeMap?.[tag.name] || tag.name;
msg.topic   = msg.pulseTopic;
msg.action  = 'write';
msg.payload = true;
return msg;

if (global.get('plcDriver') !== 'opc') return null;
const cfg = global.get('plcConfig') || {};
const tag = msg.payload?.tag;
if (!tag?.name) return null;
const nodeId = cfg.nodeMap?.[tag.name] || tag.name;
// Read current value, then invert via write
msg.toggleNodeId = nodeId;
msg.topic  = nodeId;
msg.action = 'read';
return msg;

const val = Array.isArray(msg.payload) ? msg.payload[0]?.value : msg.payload;
msg.topic   = msg.toggleNodeId;
msg.action  = 'write';
msg.payload = !val;
return msg;

const all = global.get('printerList') || flow.get('printerList') || [];
msg.payload = all.filter(p => p.snmpEnabled !== false);
if (msg.payload.length === 0)
  return null;
return msg;

msg.printer = msg.payload;
msg.host = msg.payload.ip;
msg.community = 'public';
msg.version = '2c';
msg.oids = [
    '1.3.6.1.2.1.25.3.5.1.1.1',
    '1.3.6.1.2.1.25.3.5.1.2.1',
    '1.3.6.1.2.1.1.5.0'
];
msg.timeout = 3000;
return msg;

msg.payload.lastPrint = flow.get('lastPrint_' + msg.payload.name) || null;
msg.topic = 'monitor/printer/' + msg.payload.mqttKey + '/status';
return msg;

const s = msg.payload;
const severity = s.alarm   > 0 ? 'alarm'
               : s.warning > 0 ? 'warning'
               : !s.online    ? 'offline'
               :                 'clear';

msg.topic = 'hmi/alarms/printer/' + s.mqttKey;
msg.payload = {
    printer:     s.name,
    equipment:   s.equipment,
    ip:          s.ip,
    alarm:       s.alarm,
    alarmText:   s.alarmText,
    warning:     s.warning,
    warningText: s.warningText,
    online:      s.online,
    status:      s.status,
    severity,
    timestamp:   s.lastSeen || new Date().toISOString()
};
return msg;

// Get the global printers list
const printers = global.get('printerList') || flow.get('printerList') || [];
if (printers.length === 0) {
	node.warn('printerList not loaded yet');
	return null;
} 

// Set initial state for all printers — before any poll fires                                                                                           
printers.forEach(p => {
	flow.set('printer_' + p.name, {
		name: p.name,
		ip: p.ip,
		equipment: p.equipment,
		mqttKey: p.mqttKey,
		type: p.type,
		rawPort: p.rawPort,
		status: 'UNAVAILABLE',
		alarm: 0,
		warning: 0,
		alarmText: 'None',
		warningText: 'None',
		online: false,
		failCount: 0,
		lastSeen: null
	});
});

// Emit one message per printer toward the alarm publisher                                                                                              
const messages = printers.map(p => ({
	topic: 'hmi/alarms/printer/' + p.mqttKey,
	payload: {
		printer: p.name,
		equipment: p.equipment,
		ip: p.ip,
		alarm: 0,
		alarmText: 'None',
		warning: 0,
		warningText: 'None',
		online: false,
		status: 'UNAVAILABLE',
		severity: 'offline',
		timestamp: null
	}
}));
return [messages];

const printers = global.get('printerList') || [];
const zebraPrinters = printers.filter(p => p.type === 'ZEBRA_ZT421');
if (zebraPrinters.length === 0) return null;

let sockets = context.get('zebraSockets') || {};

zebraPrinters.forEach(p => {
    if (!sockets[p.name]) {
        const connect = () => {
            const socket = new net.Socket();
            sockets[p.name] = { socket, connected: false, ready: false };
            context.set('zebraSockets', sockets);

            socket.on('connect', () => {
                sockets[p.name].connected = true;
                sockets[p.name].ready = true;
                context.set('zebraSockets', sockets);
                context.set(p.name + '_errTime', 0);
            });

            socket.on('data', (data) => {
                sockets[p.name].ready = true;
                context.set('zebraSockets', sockets);
                node.send({ payload: { raw: data.toString(), printer: p } });
            });

            socket.on('error', (err) => {
                const lastErr = context.get(p.name + '_errTime') || 0;
                if (Date.now() - lastErr > 60000) {
                    node.warn('Zebra TCP error ' + p.name + ': ' + err.message);
                    context.set(p.name + '_errTime', Date.now());
                }
                sockets[p.name].connected = false;
                context.set('zebraSockets', sockets);
            });

            socket.on('close', () => {
                node.send({ payload: { offline: true, printer: p } });
                if (sockets[p.name]) {
                    sockets[p.name].socket = null;
                    sockets[p.name].connected = false;
                    sockets[p.name].ready = false;
                    context.set('zebraSockets', sockets);
                }
                setTimeout(() => {
                    delete sockets[p.name];
                    context.set('zebraSockets', sockets);
                }, 5000);
            });

            socket.connect(p.rawPort || 9100, p.ip);
        };
        connect();
    } else {
