if (!printer) return null;

function updateMonitorStatus(newStatus) {
    const monKey = 'printer_' + printerName;
    const mon = flow.get(monKey) || {};
    flow.set(monKey, Object.assign({}, mon, { status: newStatus, lastSeen: new Date().toISOString() }));
