    flow.set(jobKey, Object.assign({}, jobState, { state: 'LABEL_READY' }));
    updateMonitorStatus('LABEL_READY');
    writes.push(
        { name: printer.equipment + '.Printer.JobDone', value: true, type: 'BOOL' },
        { name: printer.equipment + '.Printer.Label_RDY', value: true, type: 'BOOL' }
