    flow.set(jobKey, { state: 'IDLE' });
    updateMonitorStatus('IDLE');
    writes.push(
        { name: printer.equipment + '.Printer.Label_RDY', value: false, type: 'BOOL' },
        { name: printer.equipment + '.Printer.Available', value: true, type: 'BOOL' }
    );
