const mqttKey   = msg.printer.mqttKey;

const FAIL_THRESHOLD = 3;
const ALARM_TEXTS    = ['None', 'Media Empty', 'Ink Empty', 'Paper Jam', 'Error'];
const WARNING_TEXTS  = ['None', 'Media Low',   'Toner Low', 'Warning'];
const STATUS_MAP     = { 1:'OTHER', 2:'UNKNOWN', 3:'IDLE', 4:'PRINTING', 5:'WARMUP' };

