        failCount,
        online:        goOffline ? false       : prev.online,
        status:        goOffline ? 'OFFLINE'   : prev.status,
        lastSeen:      prev.lastSeen || null,
        lastPollError: msg.error ? msg.error.message : 'SNMP no response'
