    // 0x08=doorOpen  0x04=jammed    0x02=offline   0x01=serviceRequested
    let errByte = 0;
    if (Buffer.isBuffer(errBuffer) && errBuffer.length > 0) {
        errByte = errBuffer[0];
    } else if (typeof errBuffer === 'number') {
        errByte = errBuffer;
    }

