        name, ip, equipment, mqttKey,
        status:      STATUS_MAP[rawStatus] || 'UNKNOWN',
        alarm,       warning,
        alarmText:   ALARM_TEXTS[alarm]    || 'Error',
        warningText: WARNING_TEXTS[warning] || 'Warning',
        online:      true,
