    ippAttr(0x48, 'attributes-natural-language','en-us'),
    ippAttr(0x45, 'printer-uri',               uri),
    ippAttr(0x42, 'job-name',                  filePath),
    ippAttr(0x49, 'document-format',           'application/pdf'),
    Buffer.from([0x03]),                                          // end-of-attributes
    fileData
]);

msg.payload           = ippRequest;
msg.headers           = { 'Content-Type': 'application/ipp' };
msg.method            = 'POST';
msg.url               = uri;
msg.rejectUnauthorized = false;
msg._printer          = printer;
msg._filePath         = filePath;

return msg;

const printer = msg._printer;
const jobKey = 'printJob_' + printer.name;

// Network-level error (EHOSTUNREACH, ETIMEDOUT, etc.)
if (msg.error) {
    node.warn('Network error for ' + printer.name + ': ' + (msg.error.message || msg.error));
    flow.set(jobKey, { state: 'IDLE' });
    return [
        { payload: { tags: [{ name: printer.equipment + '.Printer.Available', value: true, type: 'BOOL' }] } },
        { _printerName: printer.name, _logResult: 'error', _errorMsg: msg.error.message || 'network error' }
    ];
}

if (msg.statusCode >= 200 && msg.statusCode < 300) {
    node.log('Job submitted: ' + printer.name);

    if (printer.type === 'ZEBRA_ZE511R') {
        flow.set(jobKey, { state: 'JOB_DONE' });
        return [
            { payload: { tags: [{ name: printer.equipment + '.Printer.SendDATADone', value: true, type: 'BOOL' }] } },
            { _printerName: printer.name, _logResult: 'success' }
        ];
    }

    // Epson/Zebra/Brother: completion detected by TCP polling or job monitor
    return [null, null];

} else {
    node.warn('Job error ' + msg.statusCode + ' for ' + printer.name);
    flow.set(jobKey, { state: 'IDLE' });
    return [
        { payload: { tags: [{ name: printer.equipment + '.Printer.Available', value: true, type: 'BOOL' }] } },
        { _printerName: printer.name, _logResult: 'error', _errorMsg: 'HTTP ' + msg.statusCode }
    ];
}

const printer = msg.payload.printer;
const filePath = msg.payload.filePath;
const assetsPath = global.get('printAssetsPath') || '/home/systemex/prod';
const fullPath = assetsPath + '/' + filePath;

let fileData;
try {
    fileData = fs.readFileSync(fullPath);
} catch (e) {
    node.error('Cannot read ZPL file: ' + fullPath + ' — ' + e.message);
    return null;
}

msg.payload = fileData;      // raw ZPL bytes
msg.host = printer.ip;
msg.port = printer.rawPort || 9100;
msg._printer = printer;
msg._filePath = filePath;
return msg;

const printer = msg.payload.printer;
const productName = msg.payload.productName || '';
const productQty = String(msg.payload.productQty || '');
const bacNumber = msg.payload.bacNumber || 1;

const trays = ['Tray1', 'Tray2', 'Tray3'];
const tray = trays[(bacNumber >= 1 && bacNumber <= 3) ? bacNumber - 1 : 0];

try {
    const doc = new PDFDocument({ layout: 'landscape' });
    const chunks = [];
    const pass = new stream.PassThrough();

    pass.on('data', chunk => chunks.push(chunk));
    doc.pipe(pass);

    doc.fontSize(50).text(productName, 50, 50);
    doc.fontSize(50).text(productQty, 50, 200);
    doc.fontSize(50).text(new Date().toLocaleDateString(), 50, 350);

    doc.end();

    return new Promise(resolve => {
        pass.on('end', () => {
            msg.payload = Buffer.concat(chunks);
            msg.headers = { 'Content-Type': 'application/ipp' };
            msg.method = 'POST';
            msg.url = 'http://' + printer.ip + ':631/ipp/print';
            msg.rejectUnauthorized = false;
            msg._printer = printer;
            msg._tray = tray;
            resolve(msg);
        });
        pass.on('error', err => {
            node.error('PDF stream error: ' + err.message);
            flow.set('printJob_' + printer.name, { state: 'IDLE' });
            resolve([null, {
                payload: {
                    tags: [
                        { name: printer.equipment + '.Printer.Available', value: true, type: 'BOOL' },
                        { name: printer.equipment + '.Printer.Alarm', value: 6, type: 'SINT' }
                    ]
                },
                _printerName: printer.name,
                _logResult: 'error',
                _errorMsg: 'PDF stream error: ' + err.message
            }]);
        });
    });
} catch (err) {
    node.error('PDF generation error: ' + err.message);
    flow.set('printJob_' + printer.name, { state: 'IDLE' });
    return [null, {
        payload: {
            tags: [
                { name: printer.equipment + '.Printer.Available', value: true, type: 'BOOL' },
                { name: printer.equipment + '.Printer.Alarm', value: 6, type: 'SINT' }
            ]
        },
        _printerName: printer.name,
        _logResult: 'error',
        _errorMsg: 'PDF error: ' + err.message
    }];
}

const printers = global.get('printerList') || [];
const brothers = printers.filter(p => p.type === 'BROTHER_HLL5210');

const messages = [];
brothers.forEach(p => {
    const job = flow.get('printJob_' + p.name);
    if (!job || job.state !== 'PRINTING') return;

    function ippAttr(tag, name, value) {
        const n = Buffer.from(name, 'utf8');
        const v = Buffer.from(String(value), 'utf8');
        const b = Buffer.alloc(1 + 2 + n.length + 2 + v.length);
        let o = 0;
        b.writeUInt8(tag, o++);
        b.writeUInt16BE(n.length, o); o += 2;
        n.copy(b, o); o += n.length;
        b.writeUInt16BE(v.length, o); o += 2;
        v.copy(b, o);
        return b;
    }

    const hdr = Buffer.alloc(8);
    hdr.writeUInt16BE(0x0200, 0);
    hdr.writeUInt16BE(0x000A, 2); // Get-Jobs
    hdr.writeUInt32BE(1, 4);

    messages.push({
        payload: Buffer.concat([
            hdr,
            Buffer.from([0x01]),
            ippAttr(0x47, 'attributes-charset', 'utf-8'),
            ippAttr(0x48, 'attributes-natural-language', 'en-us'),
            ippAttr(0x45, 'printer-uri', 'ipp://' + p.ip + ':631/ipp/print'),
            Buffer.from([0x03])
        ]),
        url: 'http://' + p.ip + ':631/ipp/print',
        method: 'POST',
        headers: { 'Content-Type': 'application/ipp' },
        rejectUnauthorized: false,
        _printer: p
    });
});

if (messages.length === 0) return null;
return messages;

const p = msg._printer;
if (!p) return null;

// Network-level error — silently skip, next poll will retry
if (msg.error) return null;

const jobKey = 'printJob_' + p.name;
const job = flow.get(jobKey);
if (!job || job.state !== 'PRINTING') return null;

if (msg.statusCode !== 200 || !msg.payload) return null;

const buf = msg.payload;
let hasJobs = false;
for (let i = 8; i < buf.length; i++) {
    if (buf[i] === 0x05) { hasJobs = true; break; }
}

if (!hasJobs) {
    flow.set(jobKey, { state: 'JOB_DONE' });
    node.log('Brother job done: ' + p.name);
    return [
        {
            payload: {
                tags: [
                    { name: p.equipment + '.Printer.JobDone', value: true, type: 'BOOL' },
                    { name: p.equipment + '.Printer.Available', value: true, type: 'BOOL' }
                ]
            }
        },
        { _printerName: p.name, _logResult: 'success' }
    ];
}
return null;

const tags = (msg.payload?.tags || []).filter(tag => {
    const key = 'plcLast_' + tag.name;
    const prev = flow.get(key);
    if (prev === tag.value) return false;
    flow.set(key, tag.value);
    return true;
});
if (tags.length === 0) return null;
msg.payload = { tags };
return msg;

const config = global.get('printerConfig') || {};
const TIMEOUT_MS = config.jobTimeoutMs || 120000;
const printers = global.get('printerList') || [];
const now = Date.now();
const writes = [];
const logMessages = [];

printers.forEach(p => {
    const jobKey = 'printJob_' + p.name;
    const job = flow.get(jobKey) || { state: 'IDLE' };

    if (job.state === 'PRINTING' && job.startTime && (now - job.startTime) > TIMEOUT_MS) {
        node.warn('Job timeout: ' + p.name + ' — resetting to IDLE');
        flow.set(jobKey, { state: 'IDLE' });
        logMessages.push({ _printerName: p.name, _logResult: 'timeout' });

        if (p.type === 'ZEBRA_ZE511R') {
            writes.push(
                { name: p.equipment + '.Printer.SendDATADone', value: false, type: 'BOOL' }
            );
        } else {
            writes.push(
                { name: p.equipment + '.Printer.Available', value: true, type: 'BOOL' },
                { name: p.equipment + '.Printer.JobDone', value: false, type: 'BOOL' },
                { name: p.equipment + '.Printer.Label_RDY', value: false, type: 'BOOL' }
            );
        }
    }
});

const out1 = writes.length > 0 ? { payload: { tags: writes } } : null;
const out2 = logMessages.length > 0 ? logMessages : null;
return [out1, out2];

const config = global.get('printerConfig') || {};
const printers = global.get('printerList') || [];
if (printers.length === 0) return null;

const writes = [];
printers.forEach(p => {
    flow.set('printJob_' + p.name, { state: 'IDLE' });
    const tagValues = (config.startupTags || {})[p.type] || {};
    Object.entries(tagValues).forEach(([tag, value]) => {
        writes.push({
            name: p.equipment + '.Printer.' + tag,
            value,
            type: typeof value === 'boolean' ? 'BOOL' : 'SINT'
        });
    });
});

if (writes.length === 0) return null;
msg.payload = { tags: writes };
return msg;

const printer = msg.payload.printer;
const filePath = msg.payload.filePath;

// Brother generates PDF dynamically — no file to validate
if (!printer || printer.type === 'BROTHER_HLL5210') return [msg, null];

const assetsPath = (global.get('printAssetsPath') || '/home/systemex/prod').replace(/\/+$/, '');
const fullPath = assetsPath + '/' + filePath;

if (!filePath || !fs.existsSync(fullPath)) {
    node.warn('Print file not found: ' + (fullPath || '(empty path)') + ' — ' + printer.name);
    flow.set('printJob_' + printer.name, { state: 'IDLE' });
    return [null, {
        _printerName: printer.name,
        _logResult: 'file_not_found',
        payload: {
            tags: [
                { name: printer.equipment + '.Printer.Available', value: true, type: 'BOOL' },
                { name: printer.equipment + '.Printer.Alarm', value: 6, type: 'SINT' }
            ]
        }
    }];
}
return [msg, null];

const printerName = msg._printerName;
if (!printerName) return null;

const stored = flow.get('printJobDbId_' + printerName);
if (!stored) return null;

flow.set('printJobDbId_' + printerName, null);

const result = msg._logResult || 'unknown';
const errorMsg = msg._errorMsg || null;
const now = new Date();
const durationMs = stored.startedAt ? now.getTime() - new Date(stored.startedAt).getTime() : null;

if (result === 'success') {
    flow.set('lastPrint_' + printerName, new Date().toISOString());
}

msg.params = [stored.id, now, durationMs, result, errorMsg];
return msg;

const config = global.get('printerConfig') || {};
const days = config.logRetentionDays || 30;
msg.params = [days];
return msg;

const printer = msg.payload.printer;
const filePath = msg.payload.filePath || null;
const now = new Date();

msg._printerName = printer.name;
msg._origPayload = msg.payload;
msg._startedAt = now.toISOString();
msg.params = [printer.name, printer.equipment, filePath, now];
return msg;

const row = (msg.payload || [])[0];
if (row && row.id != null) {
    flow.set('printJobDbId_' + msg._printerName, {
        id: row.id,
        startedAt: msg._startedAt
    });
}
msg.payload = msg._origPayload;
return msg;

if (!msg.payload || !msg.payload.ok) return null;
const tags = msg.payload.tags || {};

const TAG_VARIABLE_MAP = [
    { regex: /^(EQ\d+)\.PE\[1\]\.In\.Presence$/,        variable: 'sensorPresence' },
    { regex: /^(EQ\d+)\.PE\[2\]\.In\.Presence$/,        variable: 'sensorPe2Presence' },
    { regex: /^(EQ\d+)\.SeqOperation_CurrentStep$/,      variable: 'currentStep' },
    { regex: /^(EQ\d+)\.MT\[1\]\.HMI\.In\.Speed$/,     variable: 'speed' },
    { regex: /^(EQ\d+)\.CY\[\d+\]\.In\.RSX$/,          variable: 'cylinderEntered' },
    { regex: /^(EQ\d+)\.CY\[\d+\]\.In\.RSR$/,          variable: 'cylinderExited' },
    { regex: /^(EQ\d+)\.VG\[1\]\.In\.PSS$/,            variable: 'suctionCupPresence' },
    { regex: /^(EQ\d+)\.Status\.Alarm_Active$/,            variable: 'alarmActive' }
];

const messages = [];
for (const [tagName, value] of Object.entries(tags)) {
    for (const { regex, variable } of TAG_VARIABLE_MAP) {
        const match = tagName.match(regex);
        if (match) {
            // Always emit equipment/update for dashboard state
            messages.push({
                topic: 'equipment/update',
                payload: JSON.stringify({ name: match[1], tag: tagName, variable, value })
            });
            // Alarm active: also emit hmi/alarms/equipment/{name} for Integration → DB
            if (variable === 'alarmActive') {
                messages.push({
                    topic: 'hmi/alarms/equipment/' + match[1],
                    payload: value === true || value === 1 || value === 'true'
                });
            }
            break;
        }
    }
}

if (messages.length === 0) return null;
return [messages];

if (!msg.payload || !msg.payload.ok) return null;
const tags = msg.payload.tags || {};
const zoneList = global.get('zoneList') || [];
if (zoneList.length === 0) return null;
const zones = zoneList.map(z => z.name);

const COLOR_PRIORITY = {
    'Status.Alarm_Active': 1,
    'Status.Stopping':     2,
    'Status.Stopped':      2,
    'Status.Init_Done':    3,
    'Status.Paused':       3,
    'Prod_Status.Running': 4
};

const GENERAL_PRIORITY = {
    'Disabled': 1,
    'Rearmed':  2, 'Rearming': 2,
    'Init_Done':3,
    'Stopped':  4, 'Stopping': 4, 'Running': 4, 'Paused': 4
};

const SECURITY_KEYS = [
    'EStops_OK', 'EStops_Robots_OK', 'Keys_OK',
    'Doors_Closed_OK', 'Doors_Locked_OK', 'Light_Curtains_OK',
    'Coded_Magnets_OK', 'Light_Curtains_Armed', 'Air_Pressure_OK',
    'Safety_OK', 'Conditons_Arming_OK', 'Armed_Feedback_OK',
    'Dump_Valve_OK', 'Relay_Estop_OK', 'Relay_Area_OK'
];

const messages = [];

for (const zone of zones) {
    const get = (suffix) => tags[zone + '.' + suffix] === true;

    const colorEntry = Object.entries(COLOR_PRIORITY)
        .filter(([s]) => get(s))
        .sort((a, b) => a[1] - b[1])[0];
    const colorStatus = colorEntry ? colorEntry[0].split('.')[1] : 'Unknown';

    const generalEntry = Object.entries(GENERAL_PRIORITY)
        .filter(([name]) => get('Status.' + name))
        .sort((a, b) => a[1] - b[1])[0];
    const generalStatus = generalEntry ? generalEntry[0] : 'Unknown';

    const security = SECURITY_KEYS.map(k => get('Status.' + k) ? 1 : 0);
    const secStr = JSON.stringify(security);

    const prev = flow.get('zone_' + zone) || {};
    if (colorStatus   !== prev.color)   messages.push({ topic: 'zone/' + zone + '/color',    payload: colorStatus });
    if (generalStatus !== prev.general) messages.push({ topic: 'zone/' + zone + '/status',   payload: generalStatus });
    if (secStr        !== prev.secStr)  messages.push({ topic: 'zone/' + zone + '/security', payload: secStr });

    flow.set('zone_' + zone, { color: colorStatus, general: generalStatus, secStr });
}

if (messages.length === 0) return null;
return [messages.map(m => ({ topic: m.topic, payload: m.payload }))];

const body = msg.payload;
if (!body || typeof body !== 'string') return null;

function getMetric(name, labels) {
    const re = new RegExp('^' + name + (labels ? '\\{[^}]*' + labels + '[^}]*\\}' : '') + '\\s+([\\d.e+]+)', 'm');
    const m = body.match(re);
    return m ? parseFloat(m[1]) : null;
}

function getAllMetrics(name) {
    const re = new RegExp('^' + name + '\\{([^}]*)\\}\\s+([\\d.e+]+)', 'gm');
    const results = [];
    let m;
    while ((m = re.exec(body)) !== null) results.push({ labels: m[1], value: parseFloat(m[2]) });
    return results;
}

// CPU % (1 - idle / total across all CPUs)
const cpuMetrics = getAllMetrics('node_cpu_seconds_total');
let idle = 0, total = 0;
const cpuByCpu = {};
for (const { labels, value } of cpuMetrics) {
    const cpuMatch = labels.match(/cpu="(\d+)"/);
    const modeMatch = labels.match(/mode="(\w+)"/);
    if (!cpuMatch || !modeMatch) continue;
    const cpu = cpuMatch[1];
    if (!cpuByCpu[cpu]) cpuByCpu[cpu] = { idle: 0, total: 0 };
    cpuByCpu[cpu].total += value;
    if (modeMatch[1] === 'idle') cpuByCpu[cpu].idle += value;
}
const prevCpu = flow.get('prevCpu') || {};
let totalDiff = 0, idleDiff = 0;
for (const cpu of Object.keys(cpuByCpu)) {
    if (prevCpu[cpu]) {
        totalDiff += cpuByCpu[cpu].total - prevCpu[cpu].total;
        idleDiff  += cpuByCpu[cpu].idle  - prevCpu[cpu].idle;
    }
}
flow.set('prevCpu', cpuByCpu);
const cpuPct = totalDiff > 0 ? Math.round((1 - idleDiff / totalDiff) * 100) : null;

// Memory
const memTotal     = getMetric('node_memory_MemTotal_bytes');
const memAvailable = getMetric('node_memory_MemAvailable_bytes');
const memUsedPct   = memTotal && memAvailable ? Math.round((1 - memAvailable / memTotal) * 100) : null;
const memUsedGb    = memTotal && memAvailable ? ((memTotal - memAvailable) / 1073741824).toFixed(1) : null;
const memTotalGb   = memTotal ? (memTotal / 1073741824).toFixed(1) : null;

// Disk (root filesystem)
const diskAvail = getMetric('node_filesystem_avail_bytes', 'mountpoint="/"');
const diskSize  = getMetric('node_filesystem_size_bytes',  'mountpoint="/"');
const diskUsedPct = diskSize && diskAvail ? Math.round((1 - diskAvail / diskSize) * 100) : null;
const diskFreeGb  = diskAvail ? (diskAvail / 1073741824).toFixed(1) : null;
const diskTotalGb = diskSize  ? (diskSize  / 1073741824).toFixed(1) : null;

// Network (eth0 or first interface)
const rxMetrics = getAllMetrics('node_network_receive_bytes_total');
const txMetrics = getAllMetrics('node_network_transmit_bytes_total');
const prevNet = flow.get('prevNet') || {};
let rxBytes = 0, txBytes = 0;
for (const { labels, value } of rxMetrics) {
    if (labels.includes('lo')) continue;
    const prev = prevNet['rx_' + labels] || value;
    rxBytes += value - prev;
    prevNet['rx_' + labels] = value;
}
for (const { labels, value } of txMetrics) {
    if (labels.includes('lo')) continue;
    const prev = prevNet['tx_' + labels] || value;
    txBytes += value - prev;
    prevNet['tx_' + labels] = value;
}
flow.set('prevNet', prevNet);
const rxKbps = Math.round(rxBytes / 1024 / 10); // per 10s poll
const txKbps = Math.round(txBytes / 1024 / 10);

// Load average
const load1  = getMetric('node_load1');
const load5  = getMetric('node_load5');
const load15 = getMetric('node_load15');

// Uptime
const uptimeSecs = getMetric('node_time_seconds') - getMetric('node_boot_time_seconds');
const uptimeDays = uptimeSecs ? Math.floor(uptimeSecs / 86400) : null;
const uptimeHrs  = uptimeSecs ? Math.floor((uptimeSecs % 86400) / 3600) : null;

// Network history (rolling 30 points)
const netHistory = flow.get('netHistory') || [];
netHistory.push({ t: new Date().toLocaleTimeString('en', {hour:'2-digit', minute:'2-digit', second:'2-digit'}), rx: rxKbps, tx: txKbps });
if (netHistory.length > 30) netHistory.shift();
flow.set('netHistory', netHistory);

msg.payload = {
    cpuPct, memUsedPct, memUsedGb, memTotalGb,
    diskUsedPct, diskFreeGb, diskTotalGb,
    rxKbps, txKbps, load1, load5, load15,
    uptimeDays, uptimeHrs,
    netHistory,
    updatedAt: new Date().toLocaleTimeString()
};
return msg;

info:
Receives raw EIP subscription data forwarded from the Driver - EtherNet/IP tab via link node drv_em_link_out.
msg.payload = { ok: true, tags: { tagName: value, ... } }
The driver tab handles all PLC communication; this tab only processes and publishes.

Publishes to MQTT topic: equipment/update
Payload (JSON string): { name: "EQ11501", tag: "EQ11501.PE[1].In.Presence", variable: "sensorPresence", value: true }
Consumed by the Plant Monitor dashboard to update equipment card state in real time.

func:
const p = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
if (!p || !p.equipment) return null;

if (p.severity === 'clear') {
    msg.payload = {
        sql: 'UPDATE alarms SET active=false, resolved_at=NOW() WHERE equipment=$1 AND active=true',
        parameters: [p.equipment]
    };
} else {
    msg.payload = {
        sql: `INSERT INTO alarms (source, name, equipment, severity, message, alarm_code, warning_code)
              VALUES ($1, $2, $3, $4, $5, $6, $7)
              ON CONFLICT (equipment) WHERE active=true
              DO UPDATE SET severity=$4, message=$5, alarm_code=$6, warning_code=$7, created_at=CASE WHEN alarms.severity <> $4 THEN NOW() ELSE alarms.created_at END`,
        parameters: ['printer', p.printer, p.equipment, p.severity,
                     p.alarmText || p.warningText || p.severity,
                     p.alarm || 0, p.warning || 0]
    };
}
return msg;

const p = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
if (!p || !p.equipment) return null;

let bitmask = 0;
if (p.severity === 'offline') bitmask |= 1;
if (p.severity === 'alarm')   bitmask |= 2;
if (p.severity === 'warning') bitmask |= 4;

msg.payload = { tags: { [p.equipment + '.Alarms']: bitmask } };
return msg;

try {
    if (typeof msg.payload === 'string') msg.payload = JSON.parse(msg.payload);
} catch(e) { node.error('Invalid JSON'); return null; }
// Forward subscription request to driver
msg.topic = 'plc/subscribe';
return msg;

const tagName = msg.topic.replace('plc/tags/', '');
msg.payload = JSON.stringify({ topic: 'tag_update', tags: { [tagName]: msg.payload } });
return msg;

try {
    if (typeof msg.payload === 'string') msg.payload = JSON.parse(msg.payload);
} catch(e) { msg.statusCode=400; msg.payload={ok:false,error:'Invalid JSON'}; return [null,null,null,msg]; }

const type = msg.payload.type;
const ackMsg = { ...msg, statusCode: 200, payload: { ok: true } };

if (type === 'set_tag') {
    const m = { ...msg, topic:'plc/write',
        payload: { tags: [{ name: msg.payload.tag.name, value: msg.payload.tag.value, type: msg.payload.tag.type || 'BOOL' }] } };
    return [m, null, null, ackMsg];
}
if (type === 'pulse_tag') {
    const m = { ...msg, topic:'plc/pulse', payload: { tag: { name: msg.payload.tag.name } } };
    return [null, m, null, ackMsg];
}
if (type === 'toggle_tag') {
    const m = { ...msg, topic:'plc/toggle', payload: { tag: { name: msg.payload.tag.name } } };
    return [null, null, m, ackMsg];
}
// get_tag or unknown: just ack
return [null, null, null, ackMsg];

const key = msg.topic.replace('machine/alarm/', '');
msg.payload = JSON.stringify({ topic: 'alarm_update', alarm: key, active: msg.payload });
return msg;

try {
    if (typeof msg.payload === 'string') msg.payload = JSON.parse(msg.payload);
    msg.payload.args = ['skip_validation'];
} catch(e) { node.error('Invalid JSON'); return null; }
msg.topic = 'plc/subscribe';
return msg;

function bigIntToString(obj) {
    return JSON.parse(JSON.stringify(obj, (_, v) =>
        typeof v === 'bigint' ? v.toString() : v));
